	require.NoError(t, os.MkdirAll(plansDir, 0o755))

	ps, err := newTestPlanState(t, plansDir)
	require.NoError(t, err)

	const (
		targetPlan   = "solo-target.md"
		conflictPlan = "conflict.md"
		topic        = "shared-topic"
